397	// Show obtains model information, including details, modelfile, license etc.
398	func (c *Client) Show(ctx context.Context, req *ShowRequest) (*ShowResponse, error) {
399		var resp ShowResponse
400		if err := c.do(ctx, http.MethodPost, "/api/show", req, &resp); err != nil {
