406	// Heartbeat checks if the server has started and is responsive; if yes, it
407	// returns nil, otherwise an error.
408	func (c *Client) Heartbeat(ctx context.Context) error {
409		if err := c.do(ctx, http.MethodHead, "/", nil, nil); err != nil {
410			return err
411		}
412		return nil
413	}
414	
415	// Embed generates embeddings from a model.
416	func (c *Client) Embed(ctx context.Context, req *EmbedRequest) (*EmbedResponse, error) {
417		var resp EmbedResponse
418		if err := c.do(ctx, http.MethodPost, "/api/embed", req, &resp); err != nil {
419			return nil, err
420		}
421		return &resp, nil
422	}
423	
424	// Embeddings generates an embedding from a model.
425	func (c *Client) Embeddings(ctx context.Context, req *EmbeddingRequest) (*EmbeddingResponse, error) {
426		var resp EmbeddingResponse
427		if err := c.do(ctx, http.MethodPost, "/api/embeddings", req, &resp); err != nil {
428			return nil, err
429		}
430		return &resp, nil
431	}
