433	// CreateBlob creates a blob from a file on the server. digest is the
434	// expected SHA256 digest of the file, and r represents the file.
435	func (c *Client) CreateBlob(ctx context.Context, digest string, r io.Reader) error {
436		return c.do(ctx, http.MethodPost, fmt.Sprintf("/api/blobs/%s", digest), r, nil)
437	}
