439	// Version returns the Ollama server version as a string.
440	func (c *Client) Version(ctx context.Context) (string, error) {
441		var version struct {
442			Version string `json:"version"`
443		}
444	
445		if err := c.do(ctx, http.MethodGet, "/api/version", nil, &version); err != nil {
446			return "", err
447		}
448	
449		return version.Version, nil
450	}
451	
452	// CloudStatusExperimental returns whether cloud features are disabled on the server.
453	func (c *Client) CloudStatusExperimental(ctx context.Context) (*StatusResponse, error) {
454		var status StatusResponse
455		if err := c.do(ctx, http.MethodGet, "/api/status", nil, &status); err != nil {
456			return nil, err
457		}
458	
459		return &status, nil
460	}
461	
462	// Signout will signout a client for a local ollama server.
463	func (c *Client) Signout(ctx context.Context) error {
464		return c.do(ctx, http.MethodPost, "/api/signout", nil, nil)
465	}
466	
467	// Disconnect will disconnect an ollama instance from ollama.com.
468	func (c *Client) Disconnect(ctx context.Context, encodedKey string) error {
469		return c.do(ctx, http.MethodDelete, fmt.Sprintf("/api/user/keys/%s", encodedKey), nil, nil)
470	}
