347	func createBlob(cmd *cobra.Command, client *api.Client, path string, digest string, p *progress.Progress) (string, error) {
348		realPath, err := filepath.EvalSymlinks(path)
349		if err != nil {
350			return "", err
351		}
352	
353		bin, err := os.Open(realPath)
354		if err != nil {
355			return "", err
356		}
357		defer bin.Close()
358	
359		// Get file info to retrieve the size
360		fileInfo, err := bin.Stat()
361		if err != nil {
362			return "", err
363		}
364		fileSize := fileInfo.Size()
365	
366		var pw progressWriter
367		status := fmt.Sprintf("copying file %s 0%%", digest)
368		spinner := progress.NewSpinner(status)
369		p.Add(status, spinner)
370		defer spinner.Stop()
371	
372		done := make(chan struct{})
373		defer close(done)
374	
375		go func() {
376			ticker := time.NewTicker(60 * time.Millisecond)
377			defer ticker.Stop()
378			for {
379				select {
380				case <-ticker.C:
381					spinner.SetMessage(fmt.Sprintf("copying file %s %d%%", digest, int(100*pw.n.Load()/fileSize)))
382				case <-done:
383					spinner.SetMessage(fmt.Sprintf("copying file %s 100%%", digest))
384					return
385				}
386			}
387		}()
388	
389		if err := client.CreateBlob(cmd.Context(), digest, io.TeeReader(bin, &pw)); err != nil {
390			return "", err
391		}
392		return digest, nil
393	}
