### 3. MODEL REGISTRY/STORE LAYER

**Storage Structure:** Models are stored in a hierarchical directory structure under `$OLLAMA_MODELS` (default: `~/.ollama/models`):

```
$OLLAMA_MODELS/
├── manifests/
│   └── {host}/
│       └── {namespace}/
│           └── {model}/
│               └── {tag}  (manifest file)
└── blobs/
    └── {digest}  (layer data files)
```

**Manifest Discovery:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775466849324-bqmnv0/manifest/manifest.go` (lines 175-227)

```go
func Manifests(continueOnError bool) (map[model.Name]*Manifest, error) {
	manifests, err := Path()
	if err != nil {
		return nil, err
	}

	// Uses glob pattern: manifests/*/*/* to find all 4-level deep manifests
	matches, err := filepath.Glob(filepath.Join(manifests, "*", "*", "*", "*"))
	if err != nil {
		return nil, err
	}

	ms := make(map[model.Name]*Manifest)
	for _, match := range matches {
		fi, err := os.Stat(match)
		if err != nil {
			return nil, err
		}

		if !fi.IsDir() {
			rel, err := filepath.Rel(manifests, match)
			if err != nil {
				if !continueOnError {
					return nil, fmt.Errorf("%s %w", match, err)
				}
				slog.Warn("bad filepath", "path", match, "error", err)
				continue
			}

			n := model.ParseNameFromFilepath(rel)
			if !n.IsValid() {
				if !continueOnError {
					return nil, fmt.Errorf("%s %w", rel, err)
				}
				slog.Warn("bad manifest name", "path", rel)
				continue
			}

			m, err := ParseNamedManifest(n)
			// ... error handling
			ms[n] = m
		}
	}

	return ms, nil
}
```

**Model Name Resolution:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775466849324-bqmnv0/server/routes.go` (lines 1031-1053)

```go
func getExistingName(n model.Name) (model.Name, error) {
	var zero model.Name
	existing, err := manifest.Manifests(true)
	if err != nil {
		return zero, err
	}
	var set model.Name // tracks parts already canonicalized
	for e := range existing {
		if set.Host == "" && strings.EqualFold(e.Host, n.Host) {
			n.Host = e.Host
		}
		if set.Namespace == "" && strings.EqualFold(e.Namespace, n.Namespace) {
			n.Namespace = e.Namespace
		}
		if set.Model == "" && strings.EqualFold(e.Model, n.Model) {
			n.Model = e.Model
		}
		if set.Tag == "" && strings.EqualFold(e.Tag, n.Tag) {
			n.Tag = e.Tag
		}
	}
	return n, nil
}
```

This function performs **case-insensitive matching** of model names against existing manifests, preserving the actual casing on disk.

